#!/usr/bin/env bash
# project-eval-level0 — walking-skeleton exemption wrapper.
#
# Project-owned (per CLAUDE.md §Discipline edits). Not regenerated by
# `githarness update` — this file lives permanently in the project
# because the walking-skeleton exemption is a project policy, not a
# harness-level rule.
#
# Policy: ADR 002 (docs/adr/002-walking-skeleton-merge-gate-exemption.md).
#
# Why this wrapper exists
# -----------------------
# `scripts/eval-merge-gate.sh` v0.2.39 has seven gates. Three carry
# skip envs (`HARNESS_GATE_SKIP_COMPOSE`/`_API`/`_UAT`), four do not
# (gate 0 scope-discovery, gate 2 baseline, gate 3 E2E summary, gate
# 4 screenshots, gate 5 merge-comment sections). Gate 0 and gate 5
# are always satisfiable on any PR. Gates 2/3/4 require test
# infrastructure that arrives in #22 (Playwright), #23 (Newman),
# and a future UAT issue — all of which block on the walking-skeleton
# (#27, closes #1) merging. The gate is structurally unsatisfiable
# on ladder/level-0 for that reason.
#
# ADR 002 authorizes an exemption with seven preconditions. This
# wrapper enforces those preconditions, runs the real gate with the
# three existing skip envs set, and tolerates failures ONLY when
# they match the three structurally-unsatisfiable gates (2/3/4) AND
# the preconditions hold.
#
# Usage:
#   bash scripts/project-eval-level0.sh --pr <N> --issue <I> \
#        --comment-file <path> [--base latest]
#
# Environment:
#   All HARNESS_GATE_* envs pass through to scripts/eval-merge-gate.sh.
#   This wrapper hard-sets:
#     HARNESS_GATE_SKIP_COMPOSE=1
#     HARNESS_GATE_SKIP_API=1
#     HARNESS_GATE_SKIP_UAT=1
#   per ADR 002 §Decision.
#
# Exit:
#   0  — exemption preconditions met AND only structural gates failed
#   1  — preconditions missing OR a non-structural gate failed OR
#        a NEW failure was introduced by the PR
#
# DO NOT invoke this wrapper on any PR that is not ladder/level-0.
# A precondition check enforces that — the wrapper refuses to run
# if the PR's labels do not include both `ladder/level-0` and
# `priority/1`.
#
# See also:
#   - docs/adr/002-walking-skeleton-merge-gate-exemption.md
#   - scripts/eval-merge-gate.sh (githarness-managed, do not edit here)

set -uo pipefail

PR=""
ISSUE=""
COMMENT_FILE=""
BASE="latest"

while [[ $# -gt 0 ]]; do
  case "$1" in
    --pr) PR="$2"; shift 2 ;;
    --issue) ISSUE="$2"; shift 2 ;;
    --comment-file) COMMENT_FILE="$2"; shift 2 ;;
    --base) BASE="$2"; shift 2 ;;
    -h|--help)
      sed -n '2,45p' "$0"
      exit 0 ;;
    *) echo "project-eval-level0: unknown arg: $1" >&2; exit 2 ;;
  esac
done

[[ -z "$PR" ]] && { echo "project-eval-level0: --pr required" >&2; exit 2; }
[[ -z "$ISSUE" ]] && { echo "project-eval-level0: --issue required" >&2; exit 2; }
[[ -z "$COMMENT_FILE" || ! -f "$COMMENT_FILE" ]] && {
  echo "project-eval-level0: --comment-file required and must exist" >&2
  exit 2
}

HERE="$(cd "$(dirname "$0")" && pwd)"
REPO="${HARNESS_REPO:-}"
[[ -z "$REPO" ]] && { echo "project-eval-level0: HARNESS_REPO unset" >&2; exit 2; }

banner() { printf "\n=== %s ===\n" "$*"; }

# ---- Precondition 1: labels ----------------------------------
banner "precondition 1: PR labels include ladder/level-0 AND priority/1"
labels=$(gh pr view "$PR" --repo "$REPO" --json labels -q '[.labels[].name] | join(" ")' 2>/dev/null || echo '')
has_l0=$(echo " $labels " | grep -c ' ladder/level-0 ' || true)
has_p1=$(echo " $labels " | grep -c ' priority/1 ' || true)
if (( has_l0 == 0 || has_p1 == 0 )); then
  echo "  ✗ PR #$PR labels: $labels"
  echo "  ✗ Exemption REQUIRES both ladder/level-0 AND priority/1."
  echo "  ✗ Refusing to invoke exemption on a non-walking-skeleton PR."
  exit 1
fi
echo "  ✓ labels present: ladder/level-0, priority/1"

# ---- Precondition 2: issue scope-out clause ------------------
banner "precondition 2: issue #$ISSUE body scopes OUT the missing infra"
issue_body=$(gh issue view "$ISSUE" --repo "$REPO" --json body -q '.body' 2>/dev/null || echo '')
if ! echo "$issue_body" | grep -qiE 'out of scope|scope: *out|no playwright|defer.*playwright|#22|#23'; then
  echo "  ✗ issue #$ISSUE body does not contain an Out-of-scope clause"
  echo "    naming the downstream infra issues (#22 Playwright / #23 Newman)."
  echo "  ✗ Exemption requires the issue to document the scope-out"
  echo "    so the exemption's structural rationale is auditable."
  exit 1
fi
echo "  ✓ issue body contains Out-of-scope clause (or references #22/#23)"

# ---- Precondition 3: merge comment has rubric + ADR cite -----
banner "precondition 3: merge comment cites ADR 002 and rubric ≥ 75"
missing=()
grep -qiE 'ADR *002|adr/002-walking-skeleton' "$COMMENT_FILE" || missing+=("ADR 002 citation")
grep -qiE 'rubric|score.*[0-9]+/100|total:? *[7-9][0-9]|total:? *100' "$COMMENT_FILE" || missing+=("rubric total")
grep -qiE 'SKIP_COMPOSE|SKIP_API|SKIP_UAT|skip.*compose.*api.*uat' "$COMMENT_FILE" || missing+=("explicit skip-env listing")
if (( ${#missing[@]} > 0 )); then
  echo "  ✗ merge comment missing: ${missing[*]}"
  exit 1
fi
echo "  ✓ merge comment cites ADR 002, rubric, and skip envs"

# ---- Run the real gate with the three existing skip envs -----
banner "invoking scripts/eval-merge-gate.sh with exemption envs"
export HARNESS_GATE_SKIP_COMPOSE=1
export HARNESS_GATE_SKIP_API=1
export HARNESS_GATE_SKIP_UAT=1

gate_log=$(mktemp)
set +e
HARNESS_GATE_SKIP_COMPOSE=1 HARNESS_GATE_SKIP_API=1 HARNESS_GATE_SKIP_UAT=1 \
  bash "$HERE/eval-merge-gate.sh" \
    --pr "$PR" --issue "$ISSUE" \
    --comment-file "$COMMENT_FILE" \
    --base "$BASE" 2>&1 | tee "$gate_log"
gate_rc=${PIPESTATUS[0]}
set -e

# ---- Classify failures ---------------------------------------
banner "classifying gate output"
if (( gate_rc == 0 )); then
  echo "  ✓ gate passed cleanly — no exemption needed"
  rm -f "$gate_log"
  exit 0
fi

# gate_rc != 0. Extract fail reasons from the gate's `MERGE BLOCKED.
# Reasons:` block only — the gate ALSO prints an `Actions:` block
# with remediation advice that includes `  - `-prefixed bullets
# (e.g. "If NEW failures are in the PR: swap PR to claim:generator").
# Matching those remediation bullets was the rework-2 false-positive.
# We scope the extractor with sed to the Reasons block, which ends at
# the first blank line.
fail_lines=$(sed -n '/^MERGE BLOCKED\. Reasons:$/,/^$/p' "$gate_log" \
             | grep -E '^  - ' || true)
unexpected=()
while IFS= read -r line; do
  [[ -z "$line" ]] && continue
  case "$line" in
    *"no baseline cached"*|*"baseline stale"*)                        : ;;  # gate 2, expected
    *"no tests/e2e/test-results/"*|*"no E2E summary"*|*"E2E report stale"*) : ;;  # gate 3, expected
    *"no screenshots/"*|*"screenshots/"*"has"*"files; need"*|*"no recent screenshots"*) : ;;  # gate 4, expected
    *)
      unexpected+=("$line") ;;
  esac
done <<<"$fail_lines"

if (( ${#unexpected[@]} > 0 )); then
  echo ""
  echo "  ✗ EXEMPTION NOT APPLICABLE — one or more failures are outside"
  echo "    the three structurally-unsatisfiable gates (baseline / E2E /"
  echo "    screenshots):"
  printf '    %s  [non-structural OR new failure — BLOCK]\n' "${unexpected[@]}"
  echo ""
  echo "  Resolution: either fix the failure (if it's a generator bug,"
  echo "  swap claim:evaluator → claim:generator with ## 수정 요청), or"
  echo "  escalate to planner if the gate mechanics have drifted again."
  rm -f "$gate_log"
  exit 1
fi

banner "exemption APPLICABLE — structural gates only"
echo "  ✓ The failed gates are confined to the structurally-unsatisfiable"
echo "    set (baseline, E2E summary, screenshots) authorized by ADR 002."
echo "  ✓ All preconditions (labels, scope-out, rubric, ADR cite) met."
echo "  ✓ Merge authorized."
echo ""
echo "Evaluator may now run: gh pr merge $PR --merge --delete-branch"
rm -f "$gate_log"
exit 0
